# --- Application Factory ---
def create_app(config_class=SecureConfig) -> Flask:
    """Create and configure the Flask application with APM."""
    app = Flask(__name__)
    app.config.from_object(config_class)

    # Initialize database
    db.init_app(app)

    # Initialize Elastic APM with secure configuration
    apm = ElasticAPM(app)

    # Register custom APM processor to sanitize data before sending
    @app.before_request
    def before_request_handler():
        """Set up request context and validate common inputs."""
        g.request_start_time = datetime.utcnow()
        g.request_id = request.headers.get('X-Request-ID', secrets.token_hex(16))

        # Add custom context to APM transaction
        elasticapm.set_custom_context({
            'request_id': g.request_id,
            'client_ip_hash': hashlib.sha256(
                (request.remote_addr or 'unknown').encode()
            ).hexdigest()[:16],  # Hash IP for privacy
        })

        # Set user context if authenticated (without sensitive data)
        auth_user = get_authenticated_user()
        if auth_user:
            elasticapm.set_user_context(
                user_id=str(auth_user.get('id', '')),
                username=auth_user.get('username', ''),
                # Never include email or other PII in APM user context
            )

    @app.after_request
    def after_request_handler(response):
        """Add security headers and log request metrics."""
        # Security headers
        response.headers['X-Content-Type-Options'] = 'nosniff'
        response.headers['X-Frame-Options'] = 'DENY'
        response.headers['X-XSS-Protection'] = '1; mode=block'
        response.headers['Strict-Transport-Security'] = 'max-age=31536000; includeSubDomains'
        response.headers['Content-Security-Policy'] = "default-src 'self'"
        response.headers['X-Request-ID'] = g.get('request_id', 'unknown')

        # Remove server header to avoid information disclosure
        response.headers.pop('Server', None)

        # Log request duration (without sensitive data)
        if hasattr(g, 'request_start_time'):
            duration = (datetime.utcnow() - g.request_start_time).total_seconds()
            logger.info(
                "Request completed: method=%s path=%s status=%d duration=%.3fs request_id=%s",
                request.method,
                request.path,
                response.status_code,
                duration,
                g.get('request_id', 'unknown')
            )

        return response

    @app.errorhandler(Exception)
    def handle_exception(error):
        """Global error handler - never expose internal details to clients."""
        # Capture the error in APM
        elasticapm.capture_exception()

        if isinstance(error, ValidationError):
            return jsonify({
                'error': 'Validation Error',
                'details': error.messages,
                'request_id': g.get('request_id', 'unknown')
            }), 400

        if isinstance(error, HTTPException):
            return jsonify({
                'error': error.name,
                'message': error.description,
                'request_id': g.get('request_id', 'unknown')
            }), error.code

        # For unexpected errors, log details but return generic message
        logger.error(
            "Unhandled exception: %s request_id=%s",
            type(error).__name__,
            g.get('request_id', 'unknown'),
            exc_info=True
        )

        return jsonify({
            'error': 'Internal Server Error',
            'message': 'An unexpected error occurred. Please contact support.',
            'request_id': g.get('request_id', 'unknown')
        }), 500

    # Register blueprints/routes
    register_routes(app, db)

    return app


