# --- Authentication Helper ---
def get_authenticated_user() -> Optional[Dict[str, Any]]:
    """
    Validate authentication token and return user info.
    In production, this would validate JWT/OAuth tokens properly.
    """
    auth_header = request.headers.get('Authorization', '')
    if not auth_header.startswith('Bearer '):
        return None

    token = auth_header[7:]

    # Validate token format (basic check)
    if not re.match(r'^[a-zA-Z0-9._-]+$', token):
        return None

    # In production: validate JWT signature, expiry, claims, etc.
    # This is a placeholder for demonstration
    if token == os.environ.get('DEMO_API_TOKEN', ''):
        return {'id': 1, 'username': 'demo_user', 'role': 'user'}

    return None


def require_auth(f):
    """Authentication decorator."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        user = get_authenticated_user()
        if not user:
            abort(401, description='Authentication required')
        g.current_user = user
        return f(*args, **kwargs)
    return decorated_function


# --- Rate Limiting ---
class SimpleRateLimiter:
    """Simple in-memory rate limiter. Use Redis-based solution in production."""

    def __init__(self):
        self._requests: Dict[str, List[datetime]] = {}

    def is_rate_limited(self, key: str, max_requests: int, window_seconds: int = 60) -> bool:
        now = datetime.utcnow()
        cutoff = now - timedelta(seconds=window_seconds)

        if key not in self._requests:
            self._requests[key] = []

        # Clean old entries
        self._requests[key] = [t for t in self._requests[key] if t > cutoff]

        if len(self._requests[key]) >= max_requests:
            return True

        self._requests[key].append(now)
        return False


rate_limiter = SimpleRateLimiter()


def rate_limit(f):
    """Rate limiting decorator."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        # Use hashed IP as rate limit key
        client_key = hashlib.sha256(
            (request.remote_addr or 'unknown').encode()
        ).hexdigest()[:16]

        limit = SecureConfig.RATE_LIMIT_PER_MINUTE
        if rate_limiter.is_rate_limited(client_key, limit):
            logger.warning("Rate limit exceeded for client_key=%s", client_key)
            abort(429, description='Rate limit exceeded. Please try again later.')

        return f(*args, **kwargs)
    return decorated_function


# --- Sanitization Helpers ---
def sanitize_string(value: str) -> str:
    """Sanitize string input - strip HTML and dangerous characters."""
    if not isinstance(value, str):
        return ''
    # Strip HTML tags
    cleaned = bleach.clean(value, tags=[], strip=True)
    # Remove null bytes
    cleaned = cleaned.replace('\x00', '')
    return cleaned.strip()


# --- Custom APM Span Helper ---
def apm_span(name: str, span_type: str = 'app'):
    """Decorator to create custom APM spans for function tracking."""
    def decorator(f):
        @wraps(f)
        def wrapper(*args, **kwargs):
            with elasticapm.capture_span(name, span_type=span_type):
                return f(*args, **kwargs)
        return wrapper
    return decorator


# --- Routes ---
def register_routes(app: Flask, db: SQLAlchemy):
    """Register application routes."""

    @app.route('/health', methods=['GET'])
    def health_check():
        """Health check endpoint - no auth required."""
        return jsonify({
            'status': 'healthy',
            'timestamp': datetime.utcnow().isoformat()
        })

    @app.route('/api/users', methods=['GET'])
    @rate_limit
    @require_auth
    def list_users():
        """List users with pagination and search."""
        # Validate query parameters
        schema = UserQuerySchema()
        try:
            params = schema.load(request.args.to_dict())
        except ValidationError as e:
            return jsonify({'error': 'Invalid parameters', 'details': e.messages}), 400

        with elasticapm.capture_span('query_users', span_type='db'):
            query = User.query.filter_by(is_active=True)

            # Safe search - using parameterized queries (SQLAlchemy handles this)
            if params.get('search'):
                search_term = sanitize_string(params['search'])
                # Use LIKE with parameterized query - SQLAlchemy prevents SQL injection
                search_pattern = f"%{search_term}%"
                query = query.filter(
                    db.or_(
                        User.username.ilike(search_pattern),
                        User.full_name.ilike(search_pattern)
                    )
                )

            # Safe sorting - validated against allowlist
            sort_column = getattr(User, params['sort_by'])
            if params['sort_order'] == 'desc':
                sort_column = sort_column.desc()
            query = query.order_by(sort_column)

            # Pagination
            pagination = query.paginate(
                page=params['page'],
                per_page=params['per_page'],
                error_out=False
            )

        return jsonify({
            'users': [user.to_dict() for user in pagination.items],
            'pagination': {
                'page': pagination.page,
                'per_page': pagination.per_page,
                'total': pagination.total,
                'pages': pagination.pages,
            }
        })

    @app.route('/api/users', methods=['POST'])
    @rate_limit
    @require_auth
    def create_user():
        """Create a new user with validated input."""
        # Validate request body
        schema = UserCreateSchema()
        try:
            data = schema.load(request.get_json(silent=True) or {})
        except ValidationError as e:
            return jsonify({'error': 'Validation Error', 'details': e.messages}), 400

        # Sanitize string inputs
        username = sanitize_string(data['username'])
        email = data['email'].strip().lower()
        full_name = sanitize_string(data['full_name'])

        with elasticapm.capture_span('create_user', span_type='db'):
            # Check for existing user (parameterized query)
            existing = User.query.filter(
                db.or_(
                    User.username == username,
                    User.email == email
                )
            ).first()

            if existing:
                return jsonify({
                    'error': 'Conflict',
                    'message': 'A user with this username or email already exists.'
                }), 409

            user = User(
                username=username,
                email=email,
                full_name=full_name
            )
            db.session.add(user)
            db.session.commit()

        logger.info("User created: id=%d username=%s", user.id, user.username)

        # Add label to APM transaction
        elasticapm.label(action='user_created', user_id=user.id)

        return jsonify({
            'message': 'User created successfully',
            'user': user.to_dict()
        }), 201

    @app.route('/api/users/<int:user_id>', methods=['GET'])
    @rate_limit
    @require_auth
    def get_user(user_id: int):
        """Get a specific user by ID."""
        with elasticapm.capture_span('get_user', span_type='db'):
            user = User.query.filter_by(id=user_id, is_active=True).first()

        if not user:
            abort(404, description='User not found')

        # Only return private data if requesting own profile
        if g.current_user.get('id') == user_id:
            return jsonify({'user': user.to_dict_private()})

        return jsonify({'user': user.to_dict()})

